+export async function waitFor<T>(
+  condition: () => T | Promise<T>,
+  options: WaitForOptions = {}
+): Promise<T> {
+  const {
+    timeout = 5000,
+    interval = 50,
+    timeoutMessage = 'Condition not met within timeout',
