+      onError?.(lastError, attempt);
+
+      await sleep(currentBackoff);
+
+      if (exponential) {
+        currentBackoff = Math.min(currentBackoff * 2, maxBackoff);
+      }
+    }
+  }
+
+  throw lastError;
